2460   if (match(TVal, m_OneUse(m_Shuffle(m_Value(X), m_Value(Y), m_Mask(Mask)))) &&
2461       !is_contained(Mask, PoisonMaskElem) &&
2462       cast<ShuffleVectorInst>(TVal)->isSelect()) {
